import {flattenLessons} from "./catalog.js";
export function moduleLessonIds(curriculum,moduleId="module-1"){return flattenLessons(curriculum).filter(x=>x.moduleId===moduleId&&x.status==="published").map(x=>x.id)}
export function isModuleComplete(curriculum,state,moduleId="module-1"){const ids=moduleLessonIds(curriculum,moduleId);return ids.length>0&&ids.every(id=>state.lessonProgress?.[id]?.completed)}
export function createReviewSession(data,saved=null){return {items:data.questions,index:saved?.index||0,answers:saved?.answers||{},startedAt:saved?.startedAt||new Date().toISOString()}}
export function reviewDraft(session){return {index:session.index,answers:session.answers,startedAt:session.startedAt}}
export function analyzeModuleReview(session){const topics={};let points=0,correct=0;for(const q of session.items){const a=session.answers[q.id]||{};const ok=Boolean(a.completed)&&!(a.wrongCount||0)&&!(a.wrongAttempts||0);if(!topics[q.topicTag])topics[q.topicTag]={id:q.topicTag,label:q.topicLabel,correct:0,total:0};topics[q.topicTag].total++;if(ok){topics[q.topicTag].correct++;correct++}points+=a.points||0}const rows=Object.values(topics).map(x=>({...x,percent:Math.round(x.correct/x.total*100)}));return {correct,total:session.items.length,percent:Math.round(correct/session.items.length*100),points,topics:rows,completedAt:new Date().toISOString()}}
export function addReviewItem(state,lessonId,screenId){const progress=state.lessonProgress[lessonId]||(state.lessonProgress[lessonId]={});progress.reviewScreens=[...new Set([...(progress.reviewScreens||[]),screenId])];return state}
export function removeReviewItem(state,lessonId,screenId){const progress=state.lessonProgress?.[lessonId];if(progress)progress.reviewScreens=(progress.reviewScreens||[]).filter(id=>id!==screenId);return state}
export function collectReviewItems(state,lessonMap){const rows=[];for(const [lessonId,p] of Object.entries(state.lessonProgress||{})){const lesson=lessonMap.get(lessonId);if(!lesson)continue;for(const screenId of p.reviewScreens||[]){const screen=lesson.screens.find(x=>x.id===screenId);if(screen)rows.push({lessonId,lessonTitle:lesson.title,screenId,screen})}}return rows}
